__global__ void Fan1(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (size - 1 - t > globalId) {
        m_dev[size * (globalId + t + 1) + t] = a_dev[size * (globalId + t + 1) + t] / a_dev[size * t + t];
    }
}

__global__ void Fan2(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -= m_dev[size * (globalIdx + 1 + t) + t] * a_dev[size * t + (globalIdy + t)];

        if (globalIdy == 0) {
            b_dev[globalIdx + 1 + t] -= m_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] * b_dev[t];
        }
    }
}

void InitPerRun(int size, float *m) {
    for (int i = 0; i < size * size; i++) {
        m[i] = 0.0f;
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            printf("%8.2f ", ary[size * i + j]);
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        printf("%.2f ", ary[i]);
    }
    printf("\n");
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            fscanf(fp, "%f", &ary[size * i + j]);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

int main() {
    int Size, t;
    float *a = NULL, *b = NULL, *m = NULL;

    char filename[30];
    printf("Enter the data file name: ");
    scanf("%s", filename);
    printf("The file name is: %s\n", filename);

    FILE *fp = fopen(filename, "r");
    if (!fp) {
        printf("Failed to open file %s\n", filename);
        return -1;
    }

    fscanf(fp, "%d", &Size);

    a = (float *)malloc(Size * Size * sizeof(float));
    InitMat(fp, Size, a, Size, Size);
    printf("The input matrix a is:\n");
    PrintMat(a, Size, Size, Size);

    b = (float *)malloc(Size * sizeof(float));
    InitAry(fp, b, Size);
    printf("The input array b is:\n");
    PrintAry(b, Size);

    fclose(fp);

    m = (float *)malloc(Size * Size * sizeof(float));
    InitPerRun(Size, m);

    // Allocate device memory
    float *d_a, *d_b, *d_m;
    cudaError_t err;
    err = cudaMalloc((void **)&d_a, Size * Size * sizeof(float));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_a failed: %s\n", cudaGetErrorString(err));
        return -1;
    }
    err = cudaMalloc((void **)&d_b, Size * sizeof(float));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_b failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_a);
        return -1;
    }
    err = cudaMalloc((void **)&d_m, Size * Size * sizeof(float));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_m failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_a);
        cudaFree(d_b);
        return -1;
    }

    // Copy data to device
    err = cudaMemcpy(d_a, a, Size * Size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_a failed: %s\n", cudaGetErrorString(err));
        goto cleanup;
    }
    err = cudaMemcpy(d_b, b, Size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_b failed: %s\n", cudaGetErrorString(err));
        goto cleanup;
    }
    err = cudaMemcpy(d_m, m, Size * Size * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_m failed: %s\n", cudaGetErrorString(err));
        goto cleanup;
    }

    // Kernel launch parameters
    int blockSize1D = 256;
    int gridSize1D = (Size + blockSize1D - 1) / blockSize1D;

    dim3 blockSize2D(16, 16);
    dim3 gridSize2D((Size + blockSize2D.x - 1) / blockSize2D.x, (Size + blockSize2D.y - 1) / blockSize2D.y);

    for (t = 0; t < Size - 1; t++) {
        // Launch Fan1 kernel
        Fan1<<<gridSize1D, blockSize1D>>>(d_m, d_a, d_b, Size, t);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            fprintf(stderr, "Kernel launch Fan1 failed: %s\n", cudaGetErrorString(err));
            goto cleanup;
        }
        cudaDeviceSynchronize();

        // Launch Fan2 kernel
        Fan2<<<gridSize2D, blockSize2D>>>(d_m, d_a, d_b, Size, t);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            fprintf(stderr, "Kernel launch Fan2 failed: %s\n", cudaGetErrorString(err));
            goto cleanup;
        }
        cudaDeviceSynchronize();
    }

    // Copy results back to host
    err = cudaMemcpy(m, d_m, Size * Size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy m failed: %s\n", cudaGetErrorString(err));
        goto cleanup;
    }
    err = cudaMemcpy(a, d_a, Size * Size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy a failed: %s\n", cudaGetErrorString(err));
        goto cleanup;
    }
    err = cudaMemcpy(b, d_b, Size * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy b failed: %s\n", cudaGetErrorString(err));
        goto cleanup;
    }

    printf("The result of matrix m is: \n");
    PrintMat(m, Size, Size, Size);
    printf("The result of matrix a is: \n");
    PrintMat(a, Size, Size, Size);
    printf("The result of array b is: \n");
    PrintAry(b, Size);

cleanup:
    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_m);

    free(a);
    free(b);
    free(m);

    return 0;
}
